export const STATUS_EVENTS = {
    // Server section
    WAKE: 'status:wake',
    UNLOCK: 'status:unlock',
    BOOT: 'status:boot',
    SHUTDOWN: 'status:shutdown',
    REFRESH: 'status:refresh',

    // Sync section
    SYNC: 'status:sync',
    DELETE_ONE: 'status:delete-one',
    DELETE_ALL: 'status:delete-all',

    // Credential section
    SAVE: 'status:save',
    CLEAR: 'status:clear',

    // Services section
    STRAVA_SYNC: 'status:strava-sync',
    STRAVA_DISCONNECT: 'status:strava-disconnect',
    STRAVA_CONNECT: 'status:strava-connect',
} as const;

export interface StatusEventMap {
    [STATUS_EVENTS.WAKE]: undefined;
    [STATUS_EVENTS.UNLOCK]: undefined;
    [STATUS_EVENTS.BOOT]: undefined;
    [STATUS_EVENTS.SHUTDOWN]: undefined;
    [STATUS_EVENTS.REFRESH]: undefined;

    [STATUS_EVENTS.SYNC]: undefined;
    [STATUS_EVENTS.DELETE_ONE]: number;
    [STATUS_EVENTS.DELETE_ALL]: number;

    [STATUS_EVENTS.SAVE]: string;
    [STATUS_EVENTS.CLEAR]: undefined;

    [STATUS_EVENTS.STRAVA_SYNC]: undefined;
    [STATUS_EVENTS.STRAVA_DISCONNECT]: undefined;
    [STATUS_EVENTS.STRAVA_CONNECT]: undefined;
}

export type StatusEvent<K extends keyof StatusEventMap> = CustomEvent<StatusEventMap[K]>;

export function createStatusEvent<K extends keyof StatusEventMap>(
    type: K,
    detail: StatusEventMap[K]
): StatusEvent<K> {
    return new CustomEvent(type, {
        bubbles: true,
        composed: true,
        detail,
    }) as StatusEvent<K>;
}

export const createWakeEvent = () => createStatusEvent(STATUS_EVENTS.WAKE, undefined);
export const createUnlockEvent = () => createStatusEvent(STATUS_EVENTS.UNLOCK, undefined);
export const createBootEvent = () => createStatusEvent(STATUS_EVENTS.BOOT, undefined);
export const createShutdownEvent = () => createStatusEvent(STATUS_EVENTS.SHUTDOWN, undefined);
export const createRefreshEvent = () => createStatusEvent(STATUS_EVENTS.REFRESH, undefined);
export const createSyncEvent = () => createStatusEvent(STATUS_EVENTS.SYNC, undefined);
export const createDeleteOneEvent = (detail: StatusEventMap[typeof STATUS_EVENTS.DELETE_ONE]) => createStatusEvent(STATUS_EVENTS.DELETE_ONE, detail);
export const createDeleteAllEvent = (detail: StatusEventMap[typeof STATUS_EVENTS.DELETE_ALL]) => createStatusEvent(STATUS_EVENTS.DELETE_ALL, detail);
export const createSaveCredentialEvent = (detail: StatusEventMap[typeof STATUS_EVENTS.SAVE]) => createStatusEvent(STATUS_EVENTS.SAVE, detail);
export const createClearCredentialEvent = () => createStatusEvent(STATUS_EVENTS.CLEAR, undefined);
export const createStravaSyncEvent = () => createStatusEvent(STATUS_EVENTS.STRAVA_SYNC, undefined);
export const createStravaDisconnectEvent = () => createStatusEvent(STATUS_EVENTS.STRAVA_DISCONNECT, undefined);
export const createStravaConnectEvent = () => createStatusEvent(STATUS_EVENTS.STRAVA_CONNECT, undefined);

export type WakeEvent = StatusEvent<typeof STATUS_EVENTS.WAKE>;
export type UnlockEvent = StatusEvent<typeof STATUS_EVENTS.UNLOCK>;
export type BootEvent = StatusEvent<typeof STATUS_EVENTS.BOOT>;
export type ShutdownEvent = StatusEvent<typeof STATUS_EVENTS.SHUTDOWN>;
export type RefreshEvent = StatusEvent<typeof STATUS_EVENTS.REFRESH>;
export type SyncEvent = StatusEvent<typeof STATUS_EVENTS.SYNC>;
export type DeleteOneEvent = StatusEvent<typeof STATUS_EVENTS.DELETE_ONE>;
export type DeleteAllEvent = StatusEvent<typeof STATUS_EVENTS.DELETE_ALL>;
export type SaveCredentialEvent = StatusEvent<typeof STATUS_EVENTS.SAVE>;
export type ClearCredentialEvent = StatusEvent<typeof STATUS_EVENTS.CLEAR>;
export type StravaSyncEvent = StatusEvent<typeof STATUS_EVENTS.STRAVA_SYNC>;
export type StravaDisconnectEvent = StatusEvent<typeof STATUS_EVENTS.STRAVA_DISCONNECT>;
export type StravaConnectEvent = StatusEvent<typeof STATUS_EVENTS.STRAVA_CONNECT>;

declare global {
    interface HTMLElementEventMap {
        [STATUS_EVENTS.WAKE]: WakeEvent;
        [STATUS_EVENTS.UNLOCK]: UnlockEvent;
        [STATUS_EVENTS.BOOT]: BootEvent;
        [STATUS_EVENTS.SHUTDOWN]: ShutdownEvent;
        [STATUS_EVENTS.REFRESH]: RefreshEvent;
        [STATUS_EVENTS.SYNC]: SyncEvent;
        [STATUS_EVENTS.DELETE_ONE]: DeleteOneEvent;
        [STATUS_EVENTS.DELETE_ALL]: DeleteAllEvent;
        [STATUS_EVENTS.SAVE]: SaveCredentialEvent;
        [STATUS_EVENTS.CLEAR]: ClearCredentialEvent;
        [STATUS_EVENTS.STRAVA_SYNC]: StravaSyncEvent;
        [STATUS_EVENTS.STRAVA_DISCONNECT]: StravaDisconnectEvent;
        [STATUS_EVENTS.STRAVA_CONNECT]: StravaConnectEvent;
    }
}
